import hashlib
import importlib.metadata
import json
import re

items = sorted(
    (
        re.sub(r"[-_.]+", "-", str(dist.metadata.get("Name", ""))).lower(),
        dist.version,
    )
    for dist in importlib.metadata.distributions()
    if dist.metadata.get("Name")
)
encoded = json.dumps(
    items,
    ensure_ascii=True,
    separators=(",", ":"),
).encode("utf-8")
print(
    json.dumps(
        {
            "count": len(items),
            "sha256": hashlib.sha256(encoded).hexdigest(),
        }
    )
)
